class Solution(object):
    def minimumSubarrayLength(self, nums, k):
        n = len(nums)
        best = float('inf')
        for i in range(n):
            cur = 0
            for j in range(i, n):
                cur |= nums[j]
                if cur >= k:
                    best = min(best, j - i + 1)
                    break
        return best if best < float('inf') else -1
